import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"充能书页包","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/充能/充能书页包.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/充能/充能书页包.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/司书战斗手册/体系书页/充能/充能书页包.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"充能书页包",tabindex:"-1"},[p("充能书页包 "),r("a",{class:"header-anchor",href:"#充能书页包","aria-label":'Permalink to "充能书页包"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),n('<h1 id="充能书页包-1" tabindex="-1">充能书页包 <a class="header-anchor" href="#充能书页包-1" aria-label="Permalink to &quot;充能书页包&quot;">​</a></h1><p>充能书页</p><p>充能：充能是一种特殊计数，特定的书页可以消耗充能，充能至多可以拥有10层。</p><p>能源循环<br> 类型：攻击技<br> 等级：D<br> 派系：无<br> 能耗：0点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，使自身获得3层充能<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 穿刺骰：若拼点成功，则此次攻击获得决心上的附加成功*2点攻击检定上的增强加值。<br> 打击骰：若拼点成功，则获得决心上的附加成功*1点攻击检定上的增强加值。</p><p>能量轰击<br> 类型：攻击技<br> 等级：D<br> 派系：无<br> 能耗：2点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，对自身造成2点冲击点数，这些冲击点数不可被豁免。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 格挡骰：若拼点成功，则获得决心上的附加成功*1点格挡防御<br> 打击骰：若拼点成功，则获得决心上的附加成功*1点攻击检定上的增强加值。<br> 斩击骰：若拼点成功，且成功造成伤害，则消耗3层充能，并再额外对目标造成3点不可豁免的冲击点数。</p><p>腾跃速攻<br> 类型：攻击技<br> 等级：D<br> 派系：无<br> 能耗：1点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，消耗自身3层充能，并获得1点只能用于使用司书战斗手册内技艺的AP。下一幕开始时，自身额外获得6点先攻。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 斩击骰：若拼点成功，则获得决心上的附加成功*2点攻击检定上的增强加值。<br> 打击骰：若拼点成功，则获得决心上的附加成功*1点攻击检定上的增强加值。</p><p>冲击吸收<br> 等级：D<br> 派系：无<br> 能耗：2点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，使自身获得6层充能。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 格挡骰：若拼点成功，则获得决心上的附加成功*1点格挡防御。<br> 斩击骰：若拼点成功，则获得决心上的附加成功*1点攻击检定上的增强加值。</p><p>过度充能<br> 等级：C<br> 派系：无<br> 能耗：3点<br> 成分：动作<br> 动作：标准动作+杂技动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，使自身获得10层充能，并在下一幕中立即陷入眩晕状态，持续一轮，这是一个环境来源的效果，你无法免疫此效果。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 穿刺骰：若拼点成功，则获得决心上的附加成功*1点攻击上的附加成功。<br> 斩击骰：若拼点成功，则获得决心上的附加成功*1点攻击上的附加成功。<br> 穿刺骰：若拼点成功，则获得决心上的附加成功*1点攻击上的附加成功。<br> 反击防御骰：立即进入一个类招架的反击状态，无论此骰拼点成功与否，这一幕内下一次受到攻击时，招架将不再提供对于某次攻击的伤害抵销，而是在招架结算时，改为对攻击者造成等同于应得伤害抵销数目的物理严重伤害，这些伤害不能被豁免，但可以被伤害吸收等方式吸收，与招架相同，进行过一次反击后会立刻结束反击状态。并在受到攻击时立刻进行拼点，若拼点成功，则这次反击额外再造成3点不可豁免的严重伤害，并获得决心上的附加成功*1点格挡防御。</p><p>都给我上！<br> 等级：B<br> 派系：无<br> 能耗：2点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，消耗2层充能，在这一幕及下一幕中为射程内所有我方角色提供等同于决心上的附加成功*2层守护<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 格挡骰：若拼点成功，则获得1层守护。<br> 穿刺骰：若拼点成功，则获得决心上的附加成功*1点攻击上的附加成功。<br> 闪避骰：若拼点成功，则获得决心上的附加成功*1点闪避防御。</p><p>【守护】：具有守护时，即使生命中的最好状态不存在任何完好，也不会昏迷，伤势也不会自动恶化。每具有1层守护，就获得等同于人物内在支线等级数*1的物理伤害减免（D1C2…S5），同一特性或技艺提供的守护不能叠加。守护状态持续一轮。</p><p>毁灭连击<br> 等级：B<br> 派系：无<br> 能耗：3点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 使用时，消耗4层充能，并在此次攻击上获得2点附加成功。<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 穿刺骰：若拼点成功，则获得决心上的附加成功*3点攻击上的附加成功。<br> 打击骰：若拼点成功，则获得决心上的附加成功*3点攻击上的附加成功。<br> 打击骰：若拼点成功，则获得决心上的附加成功*2点攻击上的附加成功。</p><p>恶寒一击<br> 等级：B<br> 派系：无<br> 能耗：2点<br> 成分：动作<br> 动作：标准动作<br> 射程：接触范围<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 穿刺骰：若拼点成功，且成功造成伤害，则消耗至多8层充能，并对目标施加消耗充能层数点不可豁免的冲击点数。<br> 格挡骰：若拼点成功，则获得决心上的附加成功*1点格挡防御上的附加成功。</p><p>能量射线<br> 等级：A<br> 派系：无<br> 能耗：4点<br> 成分：动作<br> 动作：标准动作<br> 射程：决心上的附加成功*5米<br> 持续：1轮<br> 效果：<br> 进行一次“决心+专注+专业（书页）”攻击检定，并进行以下拼点检定：<br> 穿刺骰：特殊的，这个穿刺骰使用你的攻击检定进行拼点，目标使用强韧豁免对抗。可以反复进行拼点，每次拼点成功时，就消耗2层充能，目标就在下一幕开始时少获得2AP，这个效果最多将AP扣除至0，这是一个S级的创伤来源定身效果。<br> 若拼点成功，则获得决心上的附加成功*1点攻击检定上的增强加值和决心上的附加成功*2点攻击上的附加成功。而即使你反复拼点成功，这一效果也不会多次触发。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
